Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &PesFunFilCod.IsEmpty() print printBlockFilterPesFunFilCod EndIf If not &PesSts.IsEmpty() &FilterPesStsValueDescription = &PesSts.EnumerationDescription()
print printBlockFilterPesSts EndIf If not &PesIsFun.IsEmpty() &FilterPesIsFunValueDescription = '' Do Case Case &PesIsFun.ToString().Trim() = !"true" &FilterPesIsFunValueDescription = "Funcionários"
Case &PesIsFun.ToString().Trim() = !"false" &FilterPesIsFunValueDescription = "Todas Pessoas"
EndCase
print printBlockFilterPesIsFun EndIf If not &FiltroPesRaz.IsEmpty() print printBlockFilterFiltroPesRaz EndIf If not &PesCod.IsEmpty() print printBlockFilterPesCod EndIf If not &IncluirDemitidos.IsEmpty() &FilterIncluirDemitidosValueDescription = '' Do Case Case &IncluirDemitidos.ToString().Trim() = !"S" &FilterIncluirDemitidosValueDescription = "Incluir Demitidos"
Case &IncluirDemitidos.ToString().Trim() = !"N" &FilterIncluirDemitidosValueDescription = " Funcionários Vigêntes"
EndCase
print printBlockFilterIncluirDemitidos EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PESCPF' &PesCpf1.FromString(&GridStateDynamicFilter.Value) If not &PesCpf1.IsEmpty() &PesCpf = &PesCpf1 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector1 = !'PESSETCOD' &PesSetCod1.FromString(&GridStateDynamicFilter.Value) If not &PesSetCod1.IsEmpty() &PesSetCod = &PesSetCod1 print printBlockFilterPesSetCod EndIf Case &DynamicFiltersSelector1 = !'PESSETNOM' &PesSetNom1.FromString(&GridStateDynamicFilter.Value) If not &PesSetNom1.IsEmpty() &PesSetNom = &PesSetNom1 print printBlockFilterPesSetNom EndIf Case &DynamicFiltersSelector1 = !'PESVENINTEXT' &PesVenIntExt1.FromString(&GridStateDynamicFilter.Value) If not &PesVenIntExt1.IsEmpty() &FilterPesVenIntExt1ValueDescription = &PesVenIntExt1.EnumerationDescription()
&FilterPesVenIntExtValueDescription = &FilterPesVenIntExt1ValueDescription print printBlockFilterPesVenIntExt EndIf Case &DynamicFiltersSelector1 = !'RATCOD' &RatCod1.FromString(&GridStateDynamicFilter.Value) If not &RatCod1.IsEmpty() &RatCod = &RatCod1 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDCOD' &PesCidCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod1.IsEmpty() &PesCidCod = &PesCidCod1 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector1 = !'PESCIDNOM' &PesCidNom1.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom1.IsEmpty() &PesCidNom = &PesCidNom1 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector1 = !'PESCIDUFECOD' &PesCidUfeCod1.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod1.IsEmpty() &PesCidUfeCod = &PesCidUfeCod1 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector1 = !'PESFAN' &PesFan1.FromString(&GridStateDynamicFilter.Value) If not &PesFan1.IsEmpty() &PesFan = &PesFan1 print printBlockFilterPesFan EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PESCPF' &PesCpf2.FromString(&GridStateDynamicFilter.Value) If not &PesCpf2.IsEmpty() &PesCpf = &PesCpf2 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector2 = !'PESSETCOD' &PesSetCod2.FromString(&GridStateDynamicFilter.Value) If not &PesSetCod2.IsEmpty() &PesSetCod = &PesSetCod2 print printBlockFilterPesSetCod EndIf Case &DynamicFiltersSelector2 = !'PESSETNOM' &PesSetNom2.FromString(&GridStateDynamicFilter.Value) If not &PesSetNom2.IsEmpty() &PesSetNom = &PesSetNom2 print printBlockFilterPesSetNom EndIf Case &DynamicFiltersSelector2 = !'PESVENINTEXT' &PesVenIntExt2.FromString(&GridStateDynamicFilter.Value) If not &PesVenIntExt2.IsEmpty() &FilterPesVenIntExt2ValueDescription = &PesVenIntExt2.EnumerationDescription()
&FilterPesVenIntExtValueDescription = &FilterPesVenIntExt2ValueDescription print printBlockFilterPesVenIntExt EndIf Case &DynamicFiltersSelector2 = !'RATCOD' &RatCod2.FromString(&GridStateDynamicFilter.Value) If not &RatCod2.IsEmpty() &RatCod = &RatCod2 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDCOD' &PesCidCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod2.IsEmpty() &PesCidCod = &PesCidCod2 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector2 = !'PESCIDNOM' &PesCidNom2.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom2.IsEmpty() &PesCidNom = &PesCidNom2 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector2 = !'PESCIDUFECOD' &PesCidUfeCod2.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod2.IsEmpty() &PesCidUfeCod = &PesCidUfeCod2 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector2 = !'PESFAN' &PesFan2.FromString(&GridStateDynamicFilter.Value) If not &PesFan2.IsEmpty() &PesFan = &PesFan2 print printBlockFilterPesFan EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PESCPF' &PesCpf3.FromString(&GridStateDynamicFilter.Value) If not &PesCpf3.IsEmpty() &PesCpf = &PesCpf3 print printBlockFilterPesCpf EndIf Case &DynamicFiltersSelector3 = !'PESSETCOD' &PesSetCod3.FromString(&GridStateDynamicFilter.Value) If not &PesSetCod3.IsEmpty() &PesSetCod = &PesSetCod3 print printBlockFilterPesSetCod EndIf Case &DynamicFiltersSelector3 = !'PESSETNOM' &PesSetNom3.FromString(&GridStateDynamicFilter.Value) If not &PesSetNom3.IsEmpty() &PesSetNom = &PesSetNom3 print printBlockFilterPesSetNom EndIf Case &DynamicFiltersSelector3 = !'PESVENINTEXT' &PesVenIntExt3.FromString(&GridStateDynamicFilter.Value) If not &PesVenIntExt3.IsEmpty() &FilterPesVenIntExt3ValueDescription = &PesVenIntExt3.EnumerationDescription()
&FilterPesVenIntExtValueDescription = &FilterPesVenIntExt3ValueDescription print printBlockFilterPesVenIntExt EndIf Case &DynamicFiltersSelector3 = !'RATCOD' &RatCod3.FromString(&GridStateDynamicFilter.Value) If not &RatCod3.IsEmpty() &RatCod = &RatCod3 print printBlockFilterRatCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDCOD' &PesCidCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidCod3.IsEmpty() &PesCidCod = &PesCidCod3 print printBlockFilterPesCidCod EndIf Case &DynamicFiltersSelector3 = !'PESCIDNOM' &PesCidNom3.FromString(&GridStateDynamicFilter.Value) If not &PesCidNom3.IsEmpty() &PesCidNom = &PesCidNom3 print printBlockFilterPesCidNom EndIf Case &DynamicFiltersSelector3 = !'PESCIDUFECOD' &PesCidUfeCod3.FromString(&GridStateDynamicFilter.Value) If not &PesCidUfeCod3.IsEmpty() &PesCidUfeCod = &PesCidUfeCod3 print printBlockFilterPesCidUfeCod EndIf Case &DynamicFiltersSelector3 = !'PESFAN' &PesFan3.FromString(&GridStateDynamicFilter.Value) If not &PesFan3.IsEmpty() &PesFan = &PesFan3 print printBlockFilterPesFan EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod PesRaz when &OrderedBy = 1 order PesCod when &OrderedBy = 2 AND &OrderedDsc = False order (PesCod) when &OrderedBy = 2 AND &OrderedDsc = True order PesRaz when &OrderedBy = 3 AND &OrderedDsc = False order (PesRaz) when &OrderedBy = 3 AND &OrderedDsc = True order PesDtaAdm when &OrderedBy = 4 AND &OrderedDsc = False order (PesDtaAdm) when &OrderedBy = 4 AND &OrderedDsc = True order PesDtaDem when &OrderedBy = 5 AND &OrderedDsc = False order (PesDtaDem) when &OrderedBy = 5 AND &OrderedDsc = True
using DSWWFuncionario(&PesFunFilCod, &PesSts, &PesIsFun, &FiltroPesRaz, &PesCod, &IncluirDemitidos , &DynamicFiltersSelector1, &PesCpf1, &PesSetCod1, &PesSetNom1, &PesVenIntExt1, &RatCod1 , &PesCidCod1, &PesCidNom1, &PesCidUfeCod1, &PesFan1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &PesCpf2, &PesSetCod2, &PesSetNom2, &PesVenIntExt2, &RatCod2, &PesCidCod2 , &PesCidNom2, &PesCidUfeCod2, &PesFan2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &PesCpf3 , &PesSetCod3, &PesSetNom3, &PesVenIntExt3, &RatCod3, &PesCidCod3, &PesCidNom3 , &PesCidUfeCod3, &PesFan3) &gridPesFan = iif(PesFan.Length() > 30, Substr(PesFan,1, 30) + '...', PesFan) &gridFucCodNom = FucCodNom &gridPesSetNom = PesSetNom &GridPesTipPessoa = PesIsFun &gridPesCidNom = PesCidUfeCod.Trim() +' / '+ PesCidNom.Trim()
If PesTip = 'J' //JURIDICA &CpfCnpj = PesCnpj Else &CpfCnpj = PesCpf EndIF
&gridPesPrmFon = PesPrmFon
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFuncionarioGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFuncionarioGridState")) Else &GridState.FromXml(&Session.Get(!"WWFuncionarioGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PESFUNFILCOD" &PesFunFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESSTS" &PesSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESISFUN" &PesIsFun.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILTROPESRAZ" &FiltroPesRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"INCLUIRDEMITIDOS" &IncluirDemitidos.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
